sparql_query:
PREFIX goo:    <https://ucf-henat.github.io/GeoOutageOnto/#>
PREFIX gokg:   <http://example.org/resource#>
PREFIX xsd:    <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf:    <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs:   <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?county ?sviRecord ?socioeconomicScore ?thunderstormWindEventCount
WHERE {
  ?county a goo:County ;
          goo:locatedInState gokg:FloridaState .
  ?sviRecord a goo:SVIRecord ;
             goo:representsCounty ?county ;
             goo:sviYear 2022 ;
             goo:sviSocioeconomicTheme ?socioeconomicScore .
  FILTER (?socioeconomicScore >= 0.75)
  {
    SELECT ?county (COUNT(DISTINCT ?event) AS ?thunderstormWindEventCount)
    WHERE {
      ?event a goo:StormEventRecord ;
             goo:occurredInState gokg:FloridaState ;
             goo:occurredInCounty ?county ;
             goo:stormEventType ?eventType ;
             goo:eventStartTime ?eventStart .
      FILTER (YEAR(?eventStart) = 2022)
      FILTER (REGEX(STR(?eventType), "Thunderstorm Wind", "i"))
    }
    GROUP BY ?county
  }
  FILTER (?thunderstormWindEventCount >= 12)
}
ORDER BY DESC(?socioeconomicScore) DESC(?thunderstormWindEventCount) ?county
LIMIT 10
